  1→import { useCallback, useEffect } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { TOOLS } from '@/editor/tools';
  5→import { detectRooms } from '@/geometry/roomDetection';
  6→import { createRoom } from '@/domain/models';
  7→import { isTypingTarget } from '@/utils/keyboard';
  8→import styles from './Toolbar.module.css';
  9→
 10→function UndoIcon() {
 11→  return (
 12→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 13→      <path
 14→        d="M6 4 2.5 7.5 6 11"
 15→        fill="none"
 16→        stroke="currentColor"
 17→        strokeWidth="1.5"
 18→        strokeLinecap="round"
 19→        strokeLinejoin="round"
 20→      />
 21→      <path
 22→        d="M3 7.5h5.5A4.5 4.5 0 0 1 13 12"
 23→        fill="none"
 24→        stroke="currentColor"
 25→        strokeWidth="1.5"
 26→        strokeLinecap="round"
 27→        strokeLinejoin="round"
 28→      />
 29→    </svg>
 30→  );
 31→}
 32→
 33→function RedoIcon() {
 34→  return (
 35→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 36→      <path
 37→        d="m10 4 3.5 3.5L10 11"
 38→        fill="none"
 39→        stroke="currentColor"
 40→        strokeWidth="1.5"
 41→        strokeLinecap="round"
 42→        strokeLinejoin="round"
 43→      />
 44→      <path
 45→        d="M13 7.5H7.5A4.5 4.5 0 0 0 3 12"
 46→        fill="none"
 47→        stroke="currentColor"
 48→        strokeWidth="1.5"
 49→        strokeLinecap="round"
 50→        strokeLinejoin="round"
 51→      />
 52→    </svg>
 53→  );
 54→}
 55→
 56→function SidebarIcon() {
 57→  return (
 58→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 59→      <rect x="2" y="3" width="12" height="10" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.3" />
 60→      <path d="M6 3v10" fill="none" stroke="currentColor" strokeWidth="1.3" />
 61→    </svg>
 62→  );
 63→}
 64→
 65→function PropertiesIcon() {
 66→  return (
 67→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 68→      <rect x="2" y="3" width="12" height="10" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.3" />
 69→      <path d="M10 3v10" fill="none" stroke="currentColor" strokeWidth="1.3" />
 70→    </svg>
 71→  );
 72→}
 73→
 74→export default function Toolbar({
 75→  onNew,
 76→  onSave,
 77→  onLoad,
 78→  isSidebarCollapsed,
 79→  isPropertiesCollapsed,
 80→  onToggleSidebar,
 81→  onToggleProperties,
 82→}) {
 83→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, dispatch: editorDispatch } = useEditor();
 84→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 85→  const isPlanView = viewMode === 'plan';
 86→
 87→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 88→  const handleUndo = useCallback(() => {
 89→    if (!canUndo) return;
 90→    dispatch({ type: 'UNDO' });
 91→    editorDispatch({ type: 'DESELECT' });
 92→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 93→  }, [canUndo, dispatch, editorDispatch]);
 94→  const handleRedo = useCallback(() => {
 95→    if (!canRedo) return;
 96→    dispatch({ type: 'REDO' });
 97→    editorDispatch({ type: 'DESELECT' });
 98→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 99→  }, [canRedo, dispatch, editorDispatch]);
100→
101→  const handleDetectRooms = () => {
102→    const floor = project.floors.find(f => f.id === activeFloorId);
103→    if (!floor || floor.walls.length < 3) {
104→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
105→      return;
106→    }
107→
108→    const detected = detectRooms(floor.walls, floor.columns || []);
109→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
110→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
111→    editorDispatch({ type: 'DESELECT' });
112→    editorDispatch({
113→      type: 'SET_STATUS_MESSAGE',
114→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
115→    });
116→  };
117→
118→  useEffect(() => {
119→    const handleKeyDown = (e) => {
120→      if (!(e.ctrlKey || e.metaKey)) return;
121→      if (isTypingTarget(e.target)) return;
122→
123→      const key = e.key.toLowerCase();
124→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
125→      const isUndo = key === 'z' && !e.shiftKey;
126→      if (!isUndo && !isRedo) return;
127→
128→      e.preventDefault();
129→      if (isRedo) {
130→        handleRedo();
131→        return;
132→      }
133→      handleUndo();
134→    };
135→
136→    window.addEventListener('keydown', handleKeyDown);
137→    return () => window.removeEventListener('keydown', handleKeyDown);
138→  }, [handleRedo, handleUndo]);
139→
140→  return (
141→    <div className={styles.toolbar}>
142→      <div className={styles.group}>
143→        <button className={styles.btn} onClick={onNew}>New</button>
144→        <button
145→          className={`${styles.btn} ${styles.iconBtn}`}
146→          onClick={handleUndo}
147→          disabled={!canUndo}
148→          title="Undo (Ctrl/Cmd+Z)"
149→          aria-label="Undo"
150→        >
151→          <UndoIcon />
152→        </button>
153→        <button
154→          className={`${styles.btn} ${styles.iconBtn}`}
155→          onClick={handleRedo}
156→          disabled={!canRedo}
157→          title="Redo (Ctrl/Cmd+Shift+Z or Ctrl/Cmd+Y)"
158→          aria-label="Redo"
159→        >
160→          <RedoIcon />
161→        </button>
162→        <button className={styles.btn} onClick={onSave}>
163→          {isDirty && <span className={styles.dirtyIndicator} />}
164→          Save
165→        </button>
166→        <button className={styles.btn} onClick={onLoad}>Load</button>
167→      </div>
168→
169→      <div className={styles.group}>
170→        <button
171→          className={`${styles.btn} ${viewMode === 'plan' ? styles.active : ''}`}
172→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' })}
173→          title="Plan View"
174→        >
175→          Plan
176→        </button>
177→        <button
178→          className={`${styles.btn} ${viewMode === 'elevation_front' ? styles.active : ''}`}
179→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
180→          title="Front Elevation"
181→        >
182→          Front
183→        </button>
184→        <button
185→          className={`${styles.btn} ${viewMode === 'elevation_left' ? styles.active : ''}`}
186→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_left' })}
187→          title="Left Elevation"
188→        >
189→          Left
190→        </button>
191→        <button
192→          className={`${styles.btn} ${viewMode === 'elevation_right' ? styles.active : ''}`}
193→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_right' })}
194→          title="Right Elevation"
195→        >
196→          Right
197→        </button>
198→        <button
199→          className={`${styles.btn} ${viewMode === 'section_view' ? styles.active : ''}`}
200→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'section_view' })}
201→          title="Section View"
202→        >
203→          Section
204→        </button>
205→      </div>
206→
207→      <div className={styles.group}>
208→        <button
209→          className={`${styles.btn} ${activeTool === TOOLS.SELECT ? styles.active : ''}`}
210→          onClick={() => setTool(TOOLS.SELECT)}
211→          title="Select (V)"
212→          disabled={!isPlanView}
213→        >
214→          Select
215→        </button>
216→        <button
217→          className={`${styles.btn} ${activeTool === TOOLS.DIMENSION ? styles.active : ''}`}
218→          onClick={() => setTool(TOOLS.DIMENSION)}
219→          title="Place Dimension (M)"
220→          disabled={!isPlanView}
221→        >
222→          Dim
223→        </button>
224→        <button
225→          className={`${styles.btn} ${activeTool === TOOLS.WALL ? styles.active : ''}`}
226→          onClick={() => setTool(TOOLS.WALL)}
227→          title="Draw Wall (W)"
228→          disabled={!isPlanView}
229→        >
230→          Wall
231→        </button>
232→        <button
233→          className={`${styles.btn} ${activeTool === TOOLS.BEAM ? styles.active : ''}`}
234→          onClick={() => setTool(TOOLS.BEAM)}
235→          title="Place Beam (B)"
236→          disabled={!isPlanView}
237→        >
238→          Beam
239→        </button>
240→        <button
241→          className={`${styles.btn} ${activeTool === TOOLS.STAIR ? styles.active : ''}`}
242→          onClick={() => setTool(TOOLS.STAIR)}
243→          title="Place Stair (T)"
244→          disabled={!isPlanView}
245→        >
246→          Stair
247→        </button>
248→        <button
249→          className={`${styles.btn} ${activeTool === TOOLS.SECTION ? styles.active : ''}`}
250→          onClick={() => setTool(TOOLS.SECTION)}
251→          title="Draw Section Cut (Q)"
252→          disabled={!isPlanView}
253→        >
254→          Section
255→        </button>
256→        <button
257→          className={`${styles.btn} ${activeTool === TOOLS.SLAB ? styles.active : ''}`}
258→          onClick={() => setTool(TOOLS.SLAB)}
259→          title="Draw Slab (S)"
260→          disabled={!isPlanView}
261→        >
262→          Slab
263→        </button>
264→        <button
265→          className={`${styles.btn} ${activeTool === TOOLS.ROOM ? styles.active : ''}`}
266→          onClick={() => setTool(TOOLS.ROOM)}
267→          title="Make Room Here (R)"
268→          disabled={!isPlanView}
269→        >
270→          Room
271→        </button>
272→        <button
273→          className={`${styles.btn} ${activeTool === TOOLS.DOOR ? styles.active : ''}`}
274→          onClick={() => setTool(TOOLS.DOOR)}
275→          title="Place Door (D)"
276→          disabled={!isPlanView}
277→        >
278→          Door
279→        </button>
280→        <button
281→          className={`${styles.btn} ${activeTool === TOOLS.WINDOW ? styles.active : ''}`}
282→          onClick={() => setTool(TOOLS.WINDOW)}
283→          title="Place Window (N)"
284→          disabled={!isPlanView}
285→        >
286→          Window
287→        </button>
288→        <button
289→          className={`${styles.btn} ${activeTool === TOOLS.COLUMN ? styles.active : ''}`}
290→          onClick={() => setTool(TOOLS.COLUMN)}
291→          title="Place Column (C)"
292→          disabled={!isPlanView}
293→        >
294→          Column
295→        </button>
296→      </div>
297→
298→      <div className={styles.group}>
299→        <button
300→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''} ${styles.iconBtn}`}
301→          onClick={onToggleSidebar}
