  1→import { useState, useEffect, useCallback } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider } from './EditorProvider';
  4→import SvgCanvas from '@/renderers/SvgCanvas';
  5→import Toolbar from '@/ui/Toolbar';
  6→import Sidebar from '@/ui/Sidebar';
  7→import PropertiesPanel from '@/ui/PropertiesPanel';
  8→import Modal from '@/ui/Modal';
  9→import { createProject } from '@/domain/models';
 10→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 11→import { useAutosave } from '@/persistence/useAutosave';
 12→import { isTypingTarget } from '@/utils/keyboard';
 13→import styles from './App.module.css';
 14→
 15→function AppInner() {
 16→  const { project, isDirty, dispatch } = useProject();
 17→  const [showLoadModal, setShowLoadModal] = useState(false);
 18→  const [savedProjects, setSavedProjects] = useState([]);
 19→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
 20→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
 21→
 22→  useAutosave(project, isDirty, dispatch);
 23→
 24→  // beforeunload warning
 25→  useEffect(() => {
 26→    const handler = (e) => {
 27→      if (isDirty) {
 28→        e.preventDefault();
 29→        e.returnValue = '';
 30→      }
 31→    };
 32→    window.addEventListener('beforeunload', handler);
 33→    return () => window.removeEventListener('beforeunload', handler);
 34→  }, [isDirty]);
 35→
 36→  const handleNew = useCallback(() => {
 37→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 38→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
 39→  }, [isDirty, dispatch]);
 40→
 41→  const handleSave = useCallback(async () => {
 42→    await saveProject(project);
 43→    dispatch({ type: 'MARK_SAVED' });
 44→  }, [project, dispatch]);
 45→
 46→  // Ctrl+S save
 47→  useEffect(() => {
 48→    const handler = (e) => {
 49→      if (isTypingTarget(e.target)) return;
 50→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
 51→        e.preventDefault();
 52→        handleSave();
 53→      }
 54→    };
 55→    window.addEventListener('keydown', handler);
 56→    return () => window.removeEventListener('keydown', handler);
 57→  }, [handleSave]);
 58→
 59→  const handleLoadClick = useCallback(async () => {
 60→    setSavedProjects(await listProjects());
 61→    setShowLoadModal(true);
 62→  }, []);
 63→
 64→  const handleLoad = useCallback(async (id) => {
 65→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 66→    try {
 67→      const { project: loaded, savedAt } = await loadProject(id);
 68→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
 69→      setShowLoadModal(false);
 70→    } catch (err) {
 71→      alert('Failed to load project: ' + err.message);
 72→    }
 73→  }, [isDirty, dispatch]);
 74→
 75→  const handleDelete = useCallback(async (id, name) => {
 76→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
 77→    if (!confirmed) return;
 78→
 79→    try {
 80→      await deleteProject(id);
 81→      setSavedProjects(projects => projects.filter(project => project.id !== id));
 82→    } catch (err) {
 83→      alert('Failed to delete project: ' + err.message);
 84→    }
 85→  }, []);
 86→
 87→  const activeFloorId = project.floors[0]?.id;
 88→
 89→  return (
 90→    <EditorProvider activeFloorId={activeFloorId}>
 91→      <div
 92→        className={styles.layout}
 93→        style={{
 94→          '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 95→          '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 96→        }}
 97→      >
 98→        <div className={styles.toolbar}>
 99→          <Toolbar
100→            onNew={handleNew}
101→            onSave={handleSave}
102→            onLoad={handleLoadClick}
103→            isSidebarCollapsed={isSidebarCollapsed}
104→            isPropertiesCollapsed={isPropertiesCollapsed}
105→            onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
106→            onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
107→          />
108→        </div>
109→        <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
110→          <Sidebar />
111→        </div>
112→        <div className={styles.canvas}>
113→          <SvgCanvas />
114→        </div>
115→        <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
116→          <PropertiesPanel />
117→        </div>
118→      </div>
119→
120→      {showLoadModal && (
121→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
122→          {savedProjects.length === 0 ? (
123→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
124→              No saved projects found.
125→            </p>
126→          ) : (
127→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
128→              {savedProjects.map(p => (
129→                <div
130→                  key={p.id}
131→                  style={{
132→                    display: 'flex',
133→                    justifyContent: 'space-between',
134→                    alignItems: 'center',
135→                    padding: '10px 12px',
136→                    border: '1px solid var(--color-border)',
137→                    borderRadius: 'var(--radius-sm)',
138→                    background: 'white',
139→                    fontSize: '13px',
140→                  }}
141→                >
142→                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
143→                    <span style={{ fontWeight: 500 }}>{p.name}</span>
144→                    <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
145→                      {new Date(p.savedAt).toLocaleDateString()}
146→                    </span>
147→                  </div>
148→                  <div style={{ display: 'flex', gap: '8px' }}>
149→                    <button
150→                      onClick={() => handleLoad(p.id)}
151→                      style={{
152→                        padding: '6px 12px',
153→                        border: '1px solid var(--color-border)',
154→                        borderRadius: 'var(--radius-sm)',
155→                        cursor: 'pointer',
156→                        background: 'white',
157→                        fontSize: '12px',
158→                      }}
159→                    >
160→                      Load
161→                    </button>
162→                    <button
163→                      onClick={() => handleDelete(p.id, p.name)}
164→                      style={{
165→                        padding: '6px 12px',
166→                        border: '1px solid #d8b4b4',
167→                        borderRadius: 'var(--radius-sm)',
168→                        cursor: 'pointer',
169→                        background: '#fff5f5',
170→                        color: '#a33a3a',
171→                        fontSize: '12px',
172→                      }}
173→                    >
174→                      Delete
175→                    </button>
176→                  </div>
177→                </div>
178→              ))}
179→            </div>
180→          )}
181→          <button
182→            onClick={() => setShowLoadModal(false)}
183→            style={{
184→              marginTop: '16px',
185→              padding: '8px 16px',
186→              border: '1px solid var(--color-border)',
187→              borderRadius: 'var(--radius-sm)',
188→              cursor: 'pointer',
189→              fontSize: '13px',
190→              background: 'white',
191→            }}
192→          >
193→            Cancel
194→          </button>
195→        </Modal>
196→      )}
197→    </EditorProvider>
198→  );
199→}
200→
201→export default function App() {
202→  return (
203→    <ProjectProvider>
204→      <AppInner />
205→    </ProjectProvider>
206→  );
207→}
