21→      }}>
22→        {label}
23→      </label>
24→      <div style={{ display: 'flex', alignItems: 'center', flex: 1, gap: '4px', minWidth: 0 }}>
25→        <input
26→          type={type}
27→          value={value}
28→          onChange={handleChange}
29→          readOnly={readOnly}
30→          step={step}
31→          style={{
32→            flex: 1,
33→            minWidth: 0,
34→            height: '28px',
35→            padding: '0 8px',
