12→      if (e.button !== 0) return;
13→
14→      const floor = getFloor(activeFloorId);
15→      if (!floor) return;
16→
17→      const face = findRoomFaceAtPoint(floor.walls, floor.columns || [], modelPos);
18→      if (!face) {
19→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'No enclosed room found here.' });
20→        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { previewPoints: null } });
21→        return;
22→      }
23→
24→      const existingRoom = findExistingRoomForFace(floor.rooms, face);
25→      if (existingRoom) {
26→        editorDispatch({ type: 'SELECT_OBJECT', id: existingRoom.id, objectType: 'room' });
27→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'A room already exists in this space.' });
28→        return;
29→      }
30→
31→      const room = createRoom(`Room ${floor.rooms.length + 1}`, face.points);
32→      dispatch({ type: 'ROOM_ADD', floorId: activeFloorId, room });
33→      editorDispatch({ type: 'SELECT_OBJECT', id: room.id, objectType: 'room' });
34→      editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { previewPoints: face.points } });
35→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `Created ${room.name}.` });
36→    },
37→
38→    onMouseMove(modelPos) {
39→      const floor = getFloor(activeFloorId);
40→      if (!floor) return;
41→
42→      const face = findRoomFaceAtPoint(floor.walls, floor.columns || [], modelPos);
43→      const previewPoints = face && !findExistingRoomForFace(floor.rooms, face)
44→        ? face.points
45→        : null;
46→
47→      editorDispatch({
48→        type: 'UPDATE_TOOL_STATE',
49→        payload: { previewPoints },
50→      });
51→    },
52→
53→    onKeyDown(e) {
54→      if (e.key !== 'Escape') return;
55→      editorDispatch({
56→        type: 'UPDATE_TOOL_STATE',
