 1→import { createBeam } from '@/domain/models';
 2→import { BEAM_WIDTH, BEAM_DEPTH } from '@/domain/defaults';
 3→import { columnOutline } from '@/geometry/columnGeometry';
 4→import { pointInPolygon } from '@/geometry/polygon';
 5→
 6→function findColumnAtPoint(columns, modelPos) {
 7→  for (const column of columns || []) {
 8→    if (pointInPolygon(modelPos, columnOutline(column))) {
 9→      return column;
10→    }
11→  }
12→  return null;
13→}
14→
15→export function createBeamPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
16→  return {
17→    onMouseMove(modelPos, e, toolState) {
18→      const floor = getFloor(activeFloorId);
19→      if (!floor) return;
20→
21→      const hoveredColumn = findColumnAtPoint(floor.columns || [], modelPos);
22→      editorDispatch({
23→        type: 'UPDATE_TOOL_STATE',
24→        payload: {
25→          previewColumnId: hoveredColumn?.id || null,
26→        },
27→      });
28→    },
29→
30→    onMouseDown(modelPos, e, toolState) {
31→      if (e.button !== 0) return;
32→
33→      const floor = getFloor(activeFloorId);
34→      if (!floor) return;
35→
36→      const column = findColumnAtPoint(floor.columns || [], modelPos);
37→      if (!column) {
38→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click a column to place a beam.' });
39→        return;
40→      }
41→
42→      if (!toolState.startColumnId) {
43→        editorDispatch({
44→          type: 'UPDATE_TOOL_STATE',
45→          payload: {
46→            startColumnId: column.id,
47→            previewColumnId: column.id,
48→          },
49→        });
50→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Select the end column for the beam.' });
51→        return;
52→      }
53→
54→      if (toolState.startColumnId === column.id) {
55→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Choose a different end column.' });
56→        return;
57→      }
58→
59→      const beam = createBeam(
60→        { kind: 'column', id: toolState.startColumnId },
61→        { kind: 'column', id: column.id },
62→        BEAM_WIDTH,
63→        BEAM_DEPTH,
64→        floor.level ?? 0
65→      );
66→
67→      dispatch({ type: 'BEAM_ADD', floorId: activeFloorId, beam });
68→      editorDispatch({ type: 'SELECT_OBJECT', id: beam.id, objectType: 'beam' });
69→      editorDispatch({
70→        type: 'UPDATE_TOOL_STATE',
71→        payload: {
72→          startColumnId: null,
73→          previewColumnId: null,
74→        },
75→      });
76→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Beam created.' });
77→    },
78→
79→    onKeyDown(e) {
80→      if (e.key === 'Escape') {
81→        editorDispatch({
82→          type: 'UPDATE_TOOL_STATE',
83→          payload: {
84→            startColumnId: null,
85→            previewColumnId: null,
86→          },
87→        });
88→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
89→      }
90→    },
91→
92→    getCursor(toolState) {
93→      return toolState.startColumnId ? 'copy' : 'crosshair';
94→    },
95→  };
96→}
