 2→import { TOOLS } from './tools';
 3→import { createWallDrawHandler } from './handlers/wallDrawHandler';
 4→import { createSelectHandler } from './handlers/selectHandler';
 5→import { createDimensionPlaceHandler } from './handlers/dimensionPlaceHandler';
 6→import { createDoorPlaceHandler } from './handlers/doorPlaceHandler';
 7→import { createWindowPlaceHandler } from './handlers/windowPlaceHandler';
 8→import { createColumnPlaceHandler } from './handlers/columnPlaceHandler';
 9→import { createRoomPlaceHandler } from './handlers/roomPlaceHandler';
10→import { createBeamPlaceHandler } from './handlers/beamPlaceHandler';
11→import { createSlabPlaceHandler } from './handlers/slabPlaceHandler';
12→import { createStairPlaceHandler } from './handlers/stairPlaceHandler';
13→import { createSectionPlaceHandler } from './handlers/sectionPlaceHandler';
14→
15→function createReadOnlyHandler() {
16→  return {
17→    onMouseDown() {},
18→    onMouseMove() {},
19→    onMouseUp() {},
20→    onDoubleClick() {},
21→    onKeyDown() {},
22→    getCursor() {
23→      return 'default';
24→    },
25→  };
26→}
27→
28→export function useEditorTool({ activeTool, dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode }) {
29→  const getFloorRef = useRef(getFloor);
30→  getFloorRef.current = getFloor;
31→
32→  const handler = useMemo(() => {
33→    if (viewMode !== 'plan') {
34→      return createReadOnlyHandler();
35→    }
36→
37→    const ctx = {
38→      dispatch, editorDispatch,
39→      getFloor: (...args) => getFloorRef.current(...args),
40→      activeFloorId, viewport, snapEnabled,
41→    };
42→
43→    switch (activeTool) {
44→      case TOOLS.DIMENSION:
45→        return createDimensionPlaceHandler(ctx);
46→      case TOOLS.WALL:
47→        return createWallDrawHandler(ctx);
48→      case TOOLS.BEAM:
49→        return createBeamPlaceHandler(ctx);
50→      case TOOLS.STAIR:
51→        return createStairPlaceHandler(ctx);
52→      case TOOLS.SECTION:
53→        return createSectionPlaceHandler(ctx);
54→      case TOOLS.SLAB:
55→        return createSlabPlaceHandler(ctx);
56→      case TOOLS.ROOM:
57→        return createRoomPlaceHandler(ctx);
58→      case TOOLS.SELECT:
59→        return createSelectHandler(ctx);
60→      case TOOLS.DOOR:
61→        return createDoorPlaceHandler(ctx);
62→      case TOOLS.WINDOW:
63→        return createWindowPlaceHandler(ctx);
64→      case TOOLS.COLUMN:
65→        return createColumnPlaceHandler(ctx);
66→      default:
67→        return null;
68→    }
69→  }, [activeTool, activeFloorId, viewport.zoom, snapEnabled, viewMode]);
70→
71→  return {
72→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
73→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
74→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
75→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
76→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
77→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
78→  };
79→}
