}

.projectName:focus {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 3px var(--color-accent-subtle);
  outline: none;
}

.item {
  display: flex;
  align-items: center;
  padding: 5px var(--space-sm);
  border-radius: var(--radius-sm);
